def analyzeStocks(priceData){
    base = select
        symbol, date, close,
        (close - mavg(close, 20)) / mstd(close, 20) as zscore,
        log(close / move(close, 20)) as momentum
    from priceData
    context by symbol

    symbols = exec distinct symbol from base
    results = peach(def(sym){
        rets = exec log(close / prev(close)) from base where symbol = sym
        sharpe = avg(rets) / std(rets) * sqrt(252)
        return dict(STRING, DOUBLE, [`symbol, `sharpe], [sym, sharpe])
    }, symbols)
    return results
}
